import { useEffect, useState } from "react";

// Generated by DIRECTORY shape (`__generated__/`). No banner — the path alone
// classifies it. Its data source stays in the graph as API metadata, but its
// rendered text ("Autogenerated glyph catalog") must never win a match.
export function GlyphCatalog() {
  const [icons, setIcons] = useState<string[]>([]);

  useEffect(() => {
    fetch("/api/icons")
      .then((res) => res.json())
      .then(setIcons);
  }, []);

  return (
    <ul>
      <li>Autogenerated glyph catalog</li>
      {icons.map((i) => (
        <li key={i}>{i}</li>
      ))}
    </ul>
  );
}
